const run = $('Run persistent RSS monitoring Task').first().json;
const rows = $input.all()
  .map((item, rowIndex) => ({ record: item.json, rowIndex }))
  .filter(({ record }) => record && Object.keys(record).length > 0);

if (rows.length === 0) {
  return [{ json: { hasRecord: false, runId: run.id, runStatus: run.status, datasetId: run.defaultDatasetId } }];
}

return rows.map(({ record, rowIndex }) => {
  const hasIdentity = typeof record.itemKey === 'string' && record.itemKey.length > 0
    && typeof record.feedUrl === 'string' && record.feedUrl.length > 0;

  if (!hasIdentity) {
    const rowIdentity = `row:${rowIndex}`;
    const diagnostic = {
      recordType: 'malformed-dataset-row',
      code: 'MISSING_REQUIRED_IDENTITY',
      product: 'rss',
      runId: String(run.id ?? ''),
      datasetId: String(run.defaultDatasetId ?? ''),
      rowIndex,
      requiredFields: ['feedUrl', 'itemKey'],
    };

    return { json: {
      hasRecord: true,
      isDiagnostic: true,
      deliveryKey: `rss:diagnostic:${encodeURIComponent(String(run.id ?? 'unknown-run'))}:${rowIdentity}`,
      product: 'rss',
      sourceId: `diagnostic:${rowIdentity}`,
      sourceUrl: '',
      title: 'Malformed RSS dataset row',
      observedAt: null,
      runId: run.id,
      runStatus: run.status,
      datasetId: run.defaultDatasetId,
      payloadJson: JSON.stringify(diagnostic),
      normalized: null,
      diagnostic,
    } };
  }

  const deliveryKey = `rss:${encodeURIComponent(record.feedUrl)}:${encodeURIComponent(record.itemKey)}`;

  return { json: {
    hasRecord: true,
    isDiagnostic: false,
    deliveryKey,
    product: 'rss',
    sourceId: record.itemKey,
    sourceUrl: record.link ?? record.feedUrl,
    title: record.title ?? '',
    observedAt: record.firstSeenAt ?? record.publishedAt ?? null,
    runId: run.id,
    runStatus: run.status,
    datasetId: run.defaultDatasetId,
    payloadJson: JSON.stringify(record),
    normalized: record,
  } };
});

const run = $('Run persistent RSS monitoring Task').first().json;
const persisted = $('Prepare dataset records').all().filter((item) => item.json.hasRecord === true);
const diagnostics = persisted.filter((item) => item.json.isDiagnostic === true);
const records = persisted.filter((item) => item.json.isDiagnostic !== true);
const result = {
  runId: run.id,
  status: run.status,
  defaultDatasetId: run.defaultDatasetId ?? null,
  hasNewItems: records.length > 0,
  newItemCount: records.length,
  recordsPersisted: persisted.length,
  validRecordsPersisted: records.length,
  diagnosticRecordsPersisted: diagnostics.length,
  items: records.map((item) => item.json.normalized),
  terminalFailure: run.status !== 'SUCCEEDED',
};

if (run.status !== 'SUCCEEDED') {
  throw new Error(`Apify Task run ${run.id} finished ${run.status} after ${persisted.length} committed dataset record(s) were idempotently persisted (${diagnostics.length} malformed-row diagnostic record(s))`);
}

return [{ json: result }];

const run = $('Run persistent RSS monitoring Task').first().json;
const result = { runId: run.id, status: run.status, defaultDatasetId: null, hasNewItems: false, newItemCount: 0, recordsPersisted: 0, items: [], terminalFailure: run.status !== 'SUCCEEDED', diagnostic: 'Terminal run has no defaultDatasetId; no dataset request was attempted.' };
if (run.status !== 'SUCCEEDED') throw new Error(`Apify Task run ${run.id} finished ${run.status} without a defaultDatasetId; no records were available to ingest`);
return [{ json: result }];
